window.XILONIME_UI = window.XILONIME_UI || {};
window.XILONIME_UI.controls = "<!-- Controls -->\n    <div class=\"controls\">\n      <div class=\"search-wrap\">\n        <span class=\"search-icon\">🔍</span>\n        <input type=\"text\" class=\"search-input\" id=\"searchInput\" placeholder=\"جستجو در انیمه‌ها...\" oninput=\"scheduleRender()\">\n      </div>\n      <div class=\"filter-tabs\" id=\"filterTabs\">\n        <button class=\"filter-tab active\" data-filter=\"all\" onclick=\"setFilter('all',this)\">همه</button>\n        <button class=\"filter-tab\" data-filter=\"watching\" onclick=\"setFilter('watching',this)\">در حال تماشا</button>\n        <button class=\"filter-tab\" data-filter=\"completed\" onclick=\"setFilter('completed',this)\">تموم شده</button>\n        <button class=\"filter-tab\" data-filter=\"planned\" onclick=\"setFilter('planned',this)\">برنامه آینده</button>\n        <button class=\"filter-tab\" data-filter=\"paused\" onclick=\"setFilter('paused',this)\">متوقف شده</button>\n        <button class=\"filter-tab\" data-filter=\"dropped\" onclick=\"setFilter('dropped',this)\">رها شده</button>\n      </div>\n      <select class=\"sort-select\" id=\"sortSelect\" onchange=\"renderList()\">\n        <option value=\"date_desc\">جدیدترین</option>\n        <option value=\"date_asc\">قدیمی‌ترین</option>\n        <option value=\"name\">نام (الف-ی)</option>\n        <option value=\"rating\">بالاترین امتیاز</option>\n        <option value=\"progress\">پیشرفت</option>\n      </select>\n      <div class=\"view-toggle\">\n        <button class=\"view-btn active\" id=\"gridViewBtn\" onclick=\"setView('grid')\" data-tip=\"نمای شبکه\">▦</button>\n        <button class=\"view-btn\" id=\"listViewBtn\" onclick=\"setView('list')\" data-tip=\"نمای لیست\">☰</button>\n      </div>\n    </div>";
